+{"id":"jeffreysprompts.com-19a6","title":"Add E2E visual regression tests for UI components","description":"# Task: E2E Visual Regression Tests

## Purpose
Capture baseline screenshots of all major UI components and detect visual regressions after changes. Critical for the color migration and UX changes.

## Testing Framework
Use Playwright's built-in screenshot comparison with Percy or custom implementation.

## Test Structure

### 1. Component Screenshot Tests
```typescript
// e2e/visual/components.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Component Visual Regression', () => {

  test.describe('PromptCard', () => {
    test('light mode - default state', async ({ page }) => {
      await page.goto('/');
      await page.waitForSelector('[data-testid="prompt-card"]');

      const card = page.locator('[data-testid="prompt-card"]').first();
      await expect(card).toHaveScreenshot('prompt-card-light-default.png', {
        maxDiffPixels: 100,
      });

      console.log('[VISUAL] PromptCard light mode default - captured');
    });

    test('light mode - hover state', async ({ page }) => {
      await page.goto('/');
      const card = page.locator('[data-testid="prompt-card"]').first();
      await card.hover();

      await expect(card).toHaveScreenshot('prompt-card-light-hover.png', {
        maxDiffPixels: 100,
      });

      console.log('[VISUAL] PromptCard light mode hover - captured');
    });

    test('dark mode - default state', async ({ page }) => {
      await page.goto('/');
      await page.evaluate(() => {
        document.documentElement.classList.add('dark');
      });

      const card = page.locator('[data-testid="prompt-card"]').first();
      await expect(card).toHaveScreenshot('prompt-card-dark-default.png', {
