 {"id":"jeffreysprompts.com-tyb1","title":"Implement credential storage module for CLI","description":"## Task
Create a credential storage module that securely stores and retrieves authentication tokens for the CLI.

## Why
This is foundational for all auth features. We need:
- Secure storage location following XDG Base Directory spec
- Atomic file operations (no partial writes)
- Token expiry checking
- Graceful handling of missing/corrupt credentials

## File: `packages/cli/src/lib/credentials.ts`

### Implementation

```typescript
import { homedir } from "os";
import { join } from "path";
import { readFile, writeFile, mkdir, unlink } from "fs/promises";
import { existsSync } from "fs";

export interface Credentials {
  access_token: string;
  refresh_token?: string;
  expires_at: string;  // ISO 8601
  email: string;
  tier: "free" | "premium";
  user_id: string;
}

// XDG Base Directory compliant path
function getCredentialsPath(): string {
  const xdgConfig = process.env.XDG_CONFIG_HOME;
  const configDir = xdgConfig || join(homedir(), ".config");
  return join(configDir, "jfp", "credentials.json");
}

function getConfigDir(): string {
  const credPath = getCredentialsPath();
  return credPath.substring(0, credPath.lastIndexOf("/"));
}

/**
 * Load credentials from disk
 * Returns null if not logged in or credentials are invalid
 */
export async function loadCredentials(): Promise<Credentials | null> {
  const path = getCredentialsPath();

  if (!existsSync(path)) {
    return null;
  }

  try {
    const content = await readFile(path, "utf-8");
    const creds = JSON.parse(content) as Credentials;

    // Basic validation
    if (!creds.access_token || !creds.email) {
      return null;
    }

    return creds;
  } catch {
    // Corrupt file or parse error
    return null;
  }
}

/**
 * Check if credentials are expired
 */
export function isExpired(creds: Credentials): boolean {
  if (!creds.expires_at) return false;

  const expiresAt = new Date(creds.expires_at);
  const now = new Date();

  // Consider expired 5 minutes before actual expiry (buffer for clock skew)
  const bufferMs = 5 * 60 * 1000;
  return now.getTime() > expiresAt.getTime() - bufferMs;
}

/**
 * Save credentials to disk
 * Atomic write with temp file to prevent corruption
 */
export async function saveCredentials(creds: Credentials): Promise<void> {
  const path = getCredentialsPath();
  const dir = getConfigDir();

  // Ensure config directory exists
  if (!existsSync(dir)) {
    await mkdir(dir, { recursive: true, mode: 0o700 });
  }

  // Write atomically via temp file
  const tempPath = `${path}.tmp`;
  const content = JSON.stringify(creds, null, 2);

  await writeFile(tempPath, content, { mode: 0o600 });  // User read/write only
  await rename(tempPath, path);
}

/**
 * Clear stored credentials (logout)
 */
export async function clearCredentials(): Promise<void> {
  const path = getCredentialsPath();

  if (existsSync(path)) {
    await unlink(path);
  }
}

/**
 * Get access token for API calls
 * Returns null if not logged in
 * Handles environment variable override (for CI/CD)
 */
export async function getAccessToken(): Promise<string | null> {
  // Environment variable takes precedence (for CI/CD)
  const envToken = process.env.JFP_TOKEN;
  if (envToken) {
    return envToken;
  }

  const creds = await loadCredentials();
  if (!creds) {
    return null;
  }

  // TODO: Auto-refresh if expired (implement in later task)
  if (isExpired(creds)) {
    return null;  // Force re-login for now
  }

  return creds.access_token;
}

/**
 * Check if user is currently logged in
 */
export async function isLoggedIn(): Promise<boolean> {
  const token = await getAccessToken();
  return token !== null;
}
```

## Security Considerations
- File permissions: 0o600 (user read/write only)
- Directory permissions: 0o700 (user only)
- Atomic writes prevent partial/corrupt files
- No sensitive data in error messages
- Environment variable override for CI/CD (no file storage needed)

## Testing
- Test with missing config directory
- Test with corrupt credentials file
- Test with expired credentials
- Test environment variable override
- Test file permissions on Unix systems

## Verification
- `saveCredentials()` creates file with correct permissions
- `loadCredentials()` returns null for missing/corrupt files
- `isExpired()` correctly identifies expired tokens
- `JFP_TOKEN` env var overrides file credentials","status":"closed","priority":1,"issue_type":"task","created_at":"2026-01-10T20:09:12.171910054-05:00","created_by":"ubuntu","updated_at":"2026-01-10T20:17:10.644953186-05:00","closed_at":"2026-01-10T20:17:10.644953186-05:00","close_reason":"Credential storage module fully implemented and tested. All 33 unit tests pass. Implementation includes: Credentials interface, XDG-compliant path resolution, loadCredentials, saveCredentials, clearCredentials, isExpired, getAccessToken, isLoggedIn, getCurrentUser. Secure file permissions (0o600/0o700), atomic writes, and JFP_TOKEN env override for CI/CD."}
+{"id":"jeffreysprompts.com-tzmc","title":"Add automated color palette validation tests","description":"# Task: Automated Color Palette Validation Tests

## Purpose
Ensure color consistency is maintained going forward. These tests will catch any regression where someone accidentally uses zinc-* or improperly uses indigo-*.

## Test Types

### 1. Static Analysis Test (Jest/Vitest)
```typescript
// tests/color-consistency.test.ts
import { execSync } from 'child_process';
import { readFileSync } from 'fs';
import { glob } from 'glob';

describe('Color Palette Consistency', () => {
  const componentFiles = glob.sync('apps/web/src/components/**/*.tsx');
  const pageFiles = glob.sync('apps/web/src/app/**/*.tsx');
  const allFiles = [...componentFiles, ...pageFiles];

  // Files explicitly allowed to use zinc (none expected after migration)
  const zincAllowlist: string[] = [];

  // Files allowed to use indigo (Pro features, semantic search)
  const indigoAllowlist = [
    'SpotlightSearch.tsx', // Semantic toggle only
    'Nav.tsx', // Pro badge
    // Add specific files that intentionally use indigo
  ];

  describe('No zinc-* colors in components', () => {
    test.each(allFiles)('File %s should not contain zinc-*', (filePath) => {
      if (zincAllowlist.some(allowed => filePath.includes(allowed))) {
        return; // Skip allowlisted files
      }

      const content = readFileSync(filePath, 'utf-8');
      const zincMatches = content.match(/zinc-\d+/g) || [];

      if (zincMatches.length > 0) {
        console.log(`[FAIL] ${filePath}:`);
        console.log(`  Found zinc colors: ${[...new Set(zincMatches)].join(', ')}`);
        console.log(`  Lines:`);
        content.split('\n').forEach((line, idx) => {
          if (line.includes('zinc-')) {
            console.log(`    ${idx + 1}: ${line.trim().slice(0, 80)}`);
          }
        });
      }

      expect(zincMatches).toHaveLength(0);
    });
  });

  describe('Indigo-* only in allowed files', () => {
    test.each(allFiles)('File %s indigo usage is intentional', (filePath) => {
      const content = readFileSync(filePath, 'utf-8');
      const indigoMatches = content.match(/indigo-\d+/g) || [];

      if (indigoMatches.length > 0) {
        const isAllowed = indigoAllowlist.some(allowed => filePath.includes(allowed));

        if (!isAllowed) {
          console.log(`[FAIL] ${filePath}:`);
          console.log(`  Found indigo colors: ${[...new Set(indigoMatches)].join(', ')}`);
          console.log(`  This file is not in the indigo allowlist.`);
          console.log(`  If intentional, add to indigoAllowlist.`);
        }

        expect(isAllowed).toBe(true);
      }
    });
  });

  describe('Typography consistency', () => {
    test.each(allFiles)('File %s should not use arbitrary text sizes', (filePath) => {
      const content = readFileSync(filePath, 'utf-8');
      // Match text-[Npx] patterns
      const arbitraryTextMatches = content.match(/text-\[\d+px\]/g) || [];

      if (arbitraryTextMatches.length > 0) {
        console.log(`[FAIL] ${filePath}:`);
        console.log(`  Found arbitrary text sizes: ${[...new Set(arbitraryTextMatches)].join(', ')}`);
        console.log(`  Use standard sizes: text-xs, text-sm, text-base, text-lg, etc.`);
      }

      expect(arbitraryTextMatches).toHaveLength(0);
    });
  });
});
```

### 2. Git Hook (Pre-commit)
```bash
#!/bin/bash
# .husky/pre-commit or similar

echo "Checking color consistency..."

# Check for zinc colors in staged tsx files
ZINC_VIOLATIONS=$(git diff --cached --name-only -- '*.tsx' | xargs grep -l 'zinc-' 2>/dev/null || true)
if [ -n "$ZINC_VIOLATIONS" ]; then
  echo "ERROR: Found zinc-* colors in staged files:"
  echo "$ZINC_VIOLATIONS"
  echo ""
  echo "Please use neutral-* instead."
  exit 1
fi

# Check for arbitrary text sizes
TEXT_VIOLATIONS=$(git diff --cached --name-only -- '*.tsx' | xargs grep -l 'text-\[' 2>/dev/null || true)
if [ -n "$TEXT_VIOLATIONS" ]; then
  echo "WARNING: Found arbitrary text sizes in staged files:"
  echo "$TEXT_VIOLATIONS"
  echo ""
  echo "Consider using standard sizes: text-xs, text-sm, etc."
fi

echo "Color consistency check passed!"
```

### 3. CI Workflow Step
```yaml
# .github/workflows/ci.yml
- name: Check Color Consistency
  run: |
    echo "=== Color Palette Validation ==="

    echo "Checking for zinc-* colors..."
    ZINC_COUNT=$(grep -r 'zinc-' apps/web/src --include='*.tsx' | wc -l)
    if [ "$ZINC_COUNT" -gt 0 ]; then
      echo "Found $ZINC_COUNT zinc-* occurrences:"
      grep -rn 'zinc-' apps/web/src --include='*.tsx' | head -20
      exit 1
    fi
    echo "✓ No zinc-* colors found"

    echo "Checking for arbitrary text sizes..."
    ARBITRARY_COUNT=$(grep -rE 'text-\[[0-9]+px\]' apps/web/src --include='*.tsx' | wc -l)
    if [ "$ARBITRARY_COUNT" -gt 0 ]; then
      echo "Found $ARBITRARY_COUNT arbitrary text sizes:"
      grep -rnE 'text-\[[0-9]+px\]' apps/web/src --include='*.tsx'
      exit 1
    fi
    echo "✓ No arbitrary text sizes found"

    echo "=== All checks passed ==="
```

## Logging Details
Every test failure should log:
1. **File path**: Which file has the violation
2. **Line numbers**: Exact lines with violations
